import React, { useState, useEffect, memo } from "react";
import { motion } from "framer-motion";
import {
  ComposableMap,
  Geographies,
  Geography,
} from "react-simple-maps";
import { geoAzimuthalEqualArea, geoPath } from "d3-geo";
import { mesh, feature } from "topojson-client";

/* ─── Member data: updated from Discord roles + forms cross-reference (2026-04-19) ─── */
const MEMBER_DATA = {
  Germany:            13,
  Poland:              8,
  Italy:               8,
  Ukraine:             7,
  France:              6,
  Russia:              6,
  Netherlands:         6,
  Spain:               5,
  Portugal:            5,
  Belgium:             5,
  Bulgaria:            5,
  Sweden:              4,
  Romania:             4,
  Hungary:             3,
  Denmark:             3,
  "United Kingdom":    3,
  Norway:              2,
  Austria:             2,
  Czechia:             2,
  Latvia:              2,
  Lithuania:           2,
  Croatia:             2,
  Ireland:             2,
  Finland:             2,
  Greece:              1,
  Montenegro:          1,
  Turkey:              1,
  Luxembourg:          1,
  Slovenia:            1,
  Switzerland:         1,
  Moldova:             1,
  "Bosnia and Herz.":  1,
};

const GEO_URL = "https://cdn.jsdelivr.net/npm/world-atlas@2/countries-50m.json";

/* European countries to display */
const EUROPE_NAMES = [
  "Albania","Andorra","Armenia","Austria","Belarus","Belgium","Bosnia and Herz.",
  "Bulgaria","Croatia","Cyprus","N. Cyprus","Czech Rep.","Czechia","Denmark","Estonia",
  "Finland","France","Germany","Greece","Hungary","Iceland","Ireland",
  "Italy","Kosovo","Latvia","Lithuania","Luxembourg","Malta","Moldova",
  "Montenegro","Netherlands","North Macedonia","Macedonia","Norway","Poland","Portugal",
  "Romania","Russia","Serbia","Slovakia","Slovenia","Spain","Sweden",
  "Switzerland","Ukraine","United Kingdom","Turkey",
  "Greenland","Georgia","San Marino",
];

const TOTAL_MEMBERS = Object.values(MEMBER_DATA).reduce((a, b) => a + b, 0);

function getPercent(count) {
  if (!count || count === 0) return 0;
  return (count / TOTAL_MEMBERS) * 100;
}

function getColor(count) {
  if (!count || count === 0) return "#f2f2f2";   // very light neutral grey — clearly "no members"
  const pct = getPercent(count);
  const intensity = Math.min(pct / 25, 1);
  // Start clearly blue-tinted even at count=1, so it's distinct from the #f2f2f2 empty grey
  const r = Math.round(205 - intensity * 165);   // 205 → 40
  const g = Math.round(210 - intensity * 150);   // 210 → 60
  const b = 235;
  return `rgb(${r}, ${g}, ${b})`;
}

/* Countries that should be linked (hover one = highlight both) */
const LINKED = {
  Greenland:   "Denmark",
  Denmark:     "Denmark",
  Ukraine:     "Ukraine",
  Cyprus:      "Cyprus",
  "N. Cyprus": "Cyprus",
};

/* Tooltip labels */
const TOOLTIP_LABELS = {
  Greenland:   "Greenland (Denmark)",
  "N. Cyprus": "Cyprus",
};

function getDisplayName(name) {
  return LINKED[name] || name;
}

function getTooltipLabel(name) {
  return TOOLTIP_LABELS[name] || name;
}

function isHighlighted(name, hovered) {
  if (!hovered) return false;
  return getDisplayName(hovered) === getDisplayName(name);
}

/* ── Shared projection — matches ComposableMap config exactly ── */
const mapProjection = geoAzimuthalEqualArea()
  .rotate([-15, -52, 0])
  .center([1, 0])
  .scale(580)
  .translate([800 / 2, 480 / 2]);

const mapPathGen = geoPath().projection(mapProjection);

/* Fallback clip box for Crimea: a generous geographic rectangle that fully
   covers Russia's topojson Crimea peninsula regardless of resolution.
   Used only when the topojson MultiPolygon extraction doesn't find a
   separate Crimea ring (i.e. the Kerch Strait is simplified away). */
const crimeaClipD = mapPathGen({
  type: "Polygon",
  coordinates: [[
    [31.0, 43.5], [37.0, 43.5],
    [37.0, 47.2], [31.0, 47.2],
    [31.0, 43.5],
  ]],
});


const MapChart = memo(function MapChart() {
  const [hovered, setHovered] = useState(null);
  const [cyprusOutlineD, setCyprusOutlineD] = useState(null);
  const [crimeaFillD, setCrimeaFillD] = useState(null);

  /* ── Fractured loading ──────────────────────────────────────────────
     Render countries in small batches using requestIdleCallback so the
     browser slots each batch into idle gaps between animation frames.
     This prevents any single frame from doing too much work.
     Insets mount only after all countries are fully rendered. */
  const [renderCount, setRenderCount] = useState(0);

  useEffect(() => {
    const BATCH = 8;
    let cancelled = false;

    const addBatch = () => {
      if (cancelled) return;
      setRenderCount(prev => {
        const next = Math.min(prev + BATCH, EUROPE_NAMES.length);
        if (next < EUROPE_NAMES.length) {
          if (typeof requestIdleCallback !== "undefined") {
            requestIdleCallback(addBatch, { timeout: 500 });
          } else {
            setTimeout(addBatch, 100);
          }
        }
        return next;
      });
    };

    if (typeof requestIdleCallback !== "undefined") {
      requestIdleCallback(addBatch, { timeout: 500 });
    } else {
      setTimeout(addBatch, 50);
    }
    return () => { cancelled = true; };
  }, []);

  useEffect(() => {
    fetch(GEO_URL)
      .then(r => r.json())
      .then(topology => {
        /* ── Cyprus outer coast (Green Line excluded) ── */
        const cyprusFamily = new Set(["Cyprus", "N. Cyprus"]);
        const cyprusMesh = mesh(
          topology,
          topology.objects.countries,
          (a, b) => {
            const aC = cyprusFamily.has(a.properties?.name);
            const bC = cyprusFamily.has(b.properties?.name);
            if (a === b) return aC;
            if (aC && bC) return false; // Green Line — exclude
            return false;
          }
        );
        setCyprusOutlineD(mapPathGen(cyprusMesh));

        /* ── Crimea: try to extract as a separate MultiPolygon ring ──
           Russia's geometry is a MultiPolygon.  If the Kerch Strait is
           present at this resolution, Crimea appears as its own polygon
           component (disconnected from mainland). We identify it by
           checking whether the ring's centroid falls inside the Crimea
           geographic bounding box. */
        const countries = feature(topology, topology.objects.countries);
        const russia = countries.features.find(f => f.properties.name === "Russia");

        if (russia?.geometry?.type === "MultiPolygon") {
          const crimeaRings = russia.geometry.coordinates.filter(rings => {
            const outer = rings[0];
            const cx = outer.reduce((s, p) => s + p[0], 0) / outer.length;
            const cy = outer.reduce((s, p) => s + p[1], 0) / outer.length;
            // Crimea centroid is roughly 33–34 °E, 45 °N
            return cx > 31.5 && cx < 36.5 && cy > 44.0 && cy < 46.5;
          });

          if (crimeaRings.length > 0) {
            setCrimeaFillD(
              mapPathGen({ type: "MultiPolygon", coordinates: crimeaRings })
            );
          }
        }
      })
      .catch(() => {});
  }, []);

  const ukraineCount   = MEMBER_DATA["Ukraine"] || 0;
  const crimeaHighlight = isHighlighted("Ukraine", hovered);

  return (
    <div className="relative" style={{ transform: "translateX(-8%)" }}>
      <ComposableMap
        projection="geoAzimuthalEqualArea"
        projectionConfig={{ rotate: [-15, -52, 0], center: [1, 0], scale: 580 }}
        width={800}
        height={480}
        style={{ width: "100%", height: "auto", display: "block", margin: "0 auto" }}
      >
        {/* Fallback Crimea clip — used only when crimeaFillD is null */}
        <defs>
          <clipPath id="crimea-ukraine-clip">
            <path d={crimeaClipD} />
          </clipPath>
        </defs>

        {/* ── All European countries ── */}
        <Geographies geography={GEO_URL}>
          {({ geographies }) =>
            geographies
              .filter(geo => EUROPE_NAMES.slice(0, renderCount).includes(geo.properties.name))
              .sort(a => (a.properties.name === "N. Cyprus" ? 1 : -1))
              .map(geo => {
                const name        = geo.properties.name;
                const displayName = getDisplayName(name);
                const count       = MEMBER_DATA[name] || MEMBER_DATA[displayName] || 0;
                const highlighted = isHighlighted(name, hovered);
                const isCyprusFamily = name === "Cyprus" || name === "N. Cyprus";
                return (
                  <Geography
                    key={geo.rsmKey}
                    geography={geo}
                    onMouseEnter={() => setHovered(name)}
                    onMouseLeave={() => setHovered(null)}
                    style={{
                      default: {
                        fill: highlighted
                          ? (count > 0 ? getColor(count) : "#d4d4d4")
                          : getColor(count),
                        stroke: isCyprusFamily ? "none"
                          : (highlighted ? "rgba(0,0,0,0.5)" : "rgba(0,0,0,0.2)"),
                        strokeWidth: isCyprusFamily ? 0 : (highlighted ? 1.5 : 0.75),
                        transition: "all 0.06s ease",
                        outline: "none",
                        cursor: "pointer",
                      },
                      hover: {
                        fill: count > 0 ? getColor(count) : "#d4d4d4",
                        stroke: isCyprusFamily ? "none" : "rgba(0,0,0,0.5)",
                        strokeWidth: isCyprusFamily ? 0 : 1.5,
                        outline: "none",
                        cursor: "pointer",
                      },
                      pressed: { outline: "none" },
                    }}
                  />
                );
              })
          }
        </Geographies>

        {/* ── Cyprus outer coast (Green Line excluded via topojson mesh) ── */}
        {cyprusOutlineD && (
          <path
            d={cyprusOutlineD}
            fill="none"
            stroke={isHighlighted("Cyprus", hovered) ? "rgba(0,0,0,0.5)" : "rgba(0,0,0,0.2)"}
            strokeWidth={isHighlighted("Cyprus", hovered) ? 1.5 : 0.75}
            style={{ pointerEvents: "none", transition: "stroke 0.06s ease" }}
          />
        )}

        {/* ── Crimea as Ukraine ──
            Primary: extracted polygon ring from Russia's MultiPolygon
            (pixel-perfect; works when the Kerch Strait is present in the topojson).
            Fallback: Russia's own topology clipped to the geographic bounding box
            (no hand-drawn shape — covers 100% of Russia's Crimea with no gaps). */}
        {crimeaFillD ? (
          <>
            {/* LAYER 2 — white blanket: erases Russia's fill + stroke */}
            <path
              d={crimeaFillD}
              fill="white"
              stroke="white"
              strokeWidth={2}
              style={{ pointerEvents: "none" }}
            />

            {/* LAYER 3 — Ukraine polygon re-drawn above the white bleed so
                any white stroke that bled into Ukrainian territory is covered */}
            <Geographies geography={GEO_URL}>
              {({ geographies }) => {
                const ukraine = geographies.find(g => g.properties.name === "Ukraine");
                if (!ukraine) return null;
                const count       = MEMBER_DATA["Ukraine"] || 0;
                const highlighted = isHighlighted("Ukraine", hovered);
                return (
                  <Geography
                    geography={ukraine}
                    onMouseEnter={() => setHovered("Ukraine")}
                    onMouseLeave={() => setHovered(null)}
                    style={{
                      default: {
                        fill: highlighted ? (count > 0 ? getColor(count) : "#d4d4d4") : getColor(count),
                        stroke: highlighted ? "rgba(0,0,0,0.5)" : "rgba(0,0,0,0.2)",
                        strokeWidth: highlighted ? 1.5 : 0.75,
                        transition: "all 0.06s ease",
                        outline: "none",
                        cursor: "pointer",
                      },
                      hover: {
                        fill: count > 0 ? getColor(count) : "#d4d4d4",
                        stroke: "rgba(0,0,0,0.5)",
                        strokeWidth: 1.5,
                        outline: "none",
                        cursor: "pointer",
                      },
                      pressed: { outline: "none" },
                    }}
                  />
                );
              }}
            </Geographies>

            {/* LAYER 4 — Ukraine-coloured Crimea, true size, clean borders */}
            <path
              d={crimeaFillD}
              fill={getColor(ukraineCount)}
              stroke={crimeaHighlight ? "rgba(0,0,0,0.5)" : "rgba(0,0,0,0.2)"}
              strokeWidth={crimeaHighlight ? 1.5 : 0.75}
              style={{ transition: "fill 0.06s ease, stroke 0.06s ease", cursor: "pointer" }}
              onMouseEnter={() => setHovered("Ukraine")}
              onMouseLeave={() => setHovered(null)}
            />
          </>
        ) : (
          <Geographies geography={GEO_URL}>
            {({ geographies }) => {
              const russia = geographies.find(g => g.properties.name === "Russia");
              if (!russia) return null;
              return (
                <Geography
                  geography={russia}
                  clipPath="url(#crimea-ukraine-clip)"
                  onMouseEnter={() => setHovered("Ukraine")}
                  onMouseLeave={() => setHovered(null)}
                  style={{
                    default: {
                      fill: getColor(ukraineCount),
                      stroke: crimeaHighlight ? "rgba(0,0,0,0.5)" : "rgba(0,0,0,0.2)",
                      strokeWidth: crimeaHighlight ? 1.5 : 0.75,
                      transition: "fill 0.06s ease, stroke 0.06s ease",
                      outline: "none",
                      cursor: "pointer",
                    },
                    hover: {
                      fill: getColor(ukraineCount),
                      stroke: "rgba(0,0,0,0.5)",
                      strokeWidth: 1.5,
                      outline: "none",
                      cursor: "pointer",
                    },
                    pressed: { outline: "none" },
                  }}
                />
              );
            }}
          </Geographies>
        )}
      </ComposableMap>


      {/* Tooltip */}
      {hovered && (
        <div
          className="absolute top-4 left-1/2 -translate-x-1/2 bg-black/85 text-white px-4 py-2 rounded-sm pointer-events-none"
          style={{ zIndex: 10 }}
        >
          <span
            className="text-xs tracking-[0.15em] uppercase font-sans"
            style={{ fontWeight: 400 }}
          >
            {getTooltipLabel(hovered)}
            {(() => {
              const count = MEMBER_DATA[hovered] || MEMBER_DATA[getDisplayName(hovered)] || 0;
              if (count > 0) {
                const pct = ((count / TOTAL_MEMBERS) * 100).toFixed(1);
                return ` · ${pct}%`;
              }
              return "";
            })()}
          </span>
        </div>
      )}
    </div>
  );
});

export default function EuropeMap() {
  return (
    <section id="where-we-are" className="py-12 px-6">
      <div className="max-w-3xl mx-auto">
        <motion.p
          className="text-[0.65rem] tracking-[0.5em] uppercase text-black/25 mb-6 text-center font-sans"
          initial={{ opacity: 0 }}
          whileInView={{ opacity: 1 }}
          viewport={{ once: true, margin: "-50px" }}
          transition={{ duration: 1.2, ease: "easeOut" }}
        >
          Our Reach
        </motion.p>
        <motion.h2
          className="font-serif text-3xl sm:text-4xl md:text-5xl text-black mb-6 text-center"
          initial={{ opacity: 0, y: 8 }}
          whileInView={{ opacity: 1, y: 0 }}
          viewport={{ once: true, margin: "-50px" }}
          transition={{ duration: 1.2, ease: "easeOut" }}
        >
          Where We Are
        </motion.h2>
        <div
          className="mx-auto mb-2"
          style={{
            height: 1,
            width: 80,
            background: "linear-gradient(90deg, transparent, rgba(0,0,0,0.15), transparent)",
          }}
        />

        <motion.div
          initial={{ opacity: 0, y: 8 }}
          whileInView={{ opacity: 1, y: 0 }}
          viewport={{ once: true, margin: "-50px" }}
          transition={{ duration: 1.2, ease: "easeOut" }}
        >
          <MapChart />

          {/* Legend */}
          <div className="flex items-center justify-center gap-4 -mt-8">
            <span className="text-[0.6rem] tracking-[0.2em] uppercase text-black/30 font-sans">
              0%
            </span>
            <div
              className="rounded-sm border border-black/10"
              style={{
                width: 120,
                height: 14,
                background: "linear-gradient(90deg, rgb(180,190,235), rgb(120, 135, 235), rgb(40, 60, 235))",
              }}
            />
            <span className="text-[0.6rem] tracking-[0.2em] uppercase text-black/30 font-sans">
              25%+
            </span>
          </div>
          <p className="text-[0.55rem] tracking-[0.15em] uppercase text-black/20 font-sans text-center mt-2">
            Share of total members
          </p>
        </motion.div>
      </div>
    </section>
  );
}
